import{_ as s,W as n,X as a,a0 as e}from"./framework-174e6972.js";const d={},l=e(`<h2 id="_1-创建表" tabindex="-1"><a class="header-anchor" href="#_1-创建表" aria-hidden="true">#</a> 1. 创建表</h2><p>首先创建一张表如下，创建表的方法介绍过了，这里就不再赘述。</p><p><img src="https://pic.downk.cc/item/5e858868504f4bcb04d08c36.jpg" alt="" loading="lazy"></p><h2 id="_2-数据修改-dml" tabindex="-1"><a class="header-anchor" href="#_2-数据修改-dml" aria-hidden="true">#</a> 2. 数据修改(DML)</h2><ul><li>添加新数据</li><li>更改数据</li><li>删除数据（行）</li></ul><h3 id="_2-1-添加新数据" tabindex="-1"><a class="header-anchor" href="#_2-1-添加新数据" aria-hidden="true">#</a> 2.1. 添加新数据：</h3><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> <span class="token operator">&lt;</span> 表名 <span class="token operator">&gt;</span> 
  <span class="token punctuation">(</span><span class="token operator">&lt;</span> 列名列表 <span class="token operator">&gt;</span><span class="token punctuation">)</span>
<span class="token keyword">VALUES</span>
  <span class="token punctuation">(</span><span class="token operator">&lt;</span> 值列表 <span class="token operator">&gt;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>如：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> t_student <span class="token punctuation">(</span>
    student_id<span class="token punctuation">,</span>
    student_name<span class="token punctuation">,</span>
    student_age<span class="token punctuation">,</span>
    student_sex
  <span class="token punctuation">)</span>
<span class="token keyword">VALUES</span>
  <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&#39;大毛&#39;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">,</span> <span class="token string">&#39;男&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e85889d504f4bcb04d0b802.jpg" alt="" loading="lazy"> 其中列名可以省略，省略之后要求插入的值必须与列一一对应：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> t_student
<span class="token keyword">VALUES</span>
  <span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;王二&#39;</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token string">&#39;男&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e8588f6504f4bcb04d10c43.jpg" alt="" loading="lazy"></p><p><strong>多行数据添加：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> t_student
<span class="token keyword">VALUES</span>
  <span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">,</span> <span class="token string">&#39;张三&#39;</span><span class="token punctuation">,</span> <span class="token number">22</span><span class="token punctuation">,</span> <span class="token string">&#39;男&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">,</span> <span class="token string">&#39;李四&#39;</span><span class="token punctuation">,</span> <span class="token number">17</span><span class="token punctuation">,</span> <span class="token string">&#39;女&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">,</span> <span class="token string">&#39;王五&#39;</span><span class="token punctuation">,</span> <span class="token number">23</span><span class="token punctuation">,</span> <span class="token string">&#39;男&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e8588f6504f4bcb04d10c43.jpg" alt="" loading="lazy"></p><h3 id="_2-2-更改数据" tabindex="-1"><a class="header-anchor" href="#_2-2-更改数据" aria-hidden="true">#</a> 2.2. 更改数据：</h3><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">UPDATE</span> 表名
<span class="token keyword">SET</span>
  列<span class="token number">1</span> <span class="token operator">=</span> 新值<span class="token number">1</span><span class="token punctuation">,</span>
  列<span class="token number">2</span> <span class="token operator">=</span> 新值<span class="token number">2</span>
<span class="token keyword">WHERE</span>
  过滤条件
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>假如要修改李四的年龄为21岁</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">UPDATE</span> t_student
<span class="token keyword">SET</span>
  student_age <span class="token operator">=</span> <span class="token number">21</span>
<span class="token keyword">WHERE</span>
  student_name <span class="token operator">=</span> <span class="token string">&#39;李四&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e858953504f4bcb04d15f04.jpg" alt="" loading="lazy"></p><div class="hint-container warning"><p class="hint-container-title">注意</p><p>修改多个列的值时用逗号隔开。要想设置某一列的值为空，只需让<code>&lt;列名&gt;=NULL</code> 即可。<code>WHERE</code>表示过滤条件。</p></div><h3 id="_2-3-删除数据-行" tabindex="-1"><a class="header-anchor" href="#_2-3-删除数据-行" aria-hidden="true">#</a> 2.3. 删除数据（行）</h3><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">DELETE</span> <span class="token keyword">FROM</span> 表名
<span class="token keyword">WHERE</span>
  过滤条件
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>现要删除20到22岁的学生信息：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">DELETE</span> <span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  student_age <span class="token operator">BETWEEN</span> <span class="token number">20</span>
  <span class="token operator">AND</span> <span class="token number">22</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e8589b5504f4bcb04d1aa51.jpg" alt="" loading="lazy"></p><p><code>WHERE</code>的判断条件之后会更详细的介绍。</p><p>删除除了<code>DELETE</code>还有一种方法<code>TRUNCATE</code>，写法：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">TRUNCATE</span> <span class="token keyword">TABLE</span> 表名<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>二者区别在于：</strong><code>DELETE</code>会记录日志，意味着删除后的数据还可以恢复，但是效率低。<code>TRUNCATE</code>不会记录日志，删除后的数据不能恢复，但是效率高。需要注意的是，<code>TRUNCATE</code>不能用于有外键约束引用的表。</p><h2 id="_3-查询操作-dql" tabindex="-1"><a class="header-anchor" href="#_3-查询操作-dql" aria-hidden="true">#</a> 3. 查询操作(DQL)</h2><h3 id="_3-1-基本查询" tabindex="-1"><a class="header-anchor" href="#_3-1-基本查询" aria-hidden="true">#</a> 3.1. 基本查询</h3><p>要查询数据库表的数据，我们使用如下的SQL语句：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> <span class="token operator">&lt;</span>表名<span class="token operator">&gt;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>要查询<code>t_students</code>表的所有行，我们用如下SQL语句：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> t_students<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>其中<code>SELECT</code>是关键字，表示将要执行一个查询，<code>*</code>表示“所有列（字段）”，<code>FROM</code>表示将要从哪个表查询，本例中是<code>t_students</code>表。</p><p>该SQL将查询出<code>t_students</code>表的所有数据。</p><p>再来看一条查询语句。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token number">100</span><span class="token operator">+</span><span class="token number">200</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>上述查询会直接计算出表达式的结果<code>300</code>。虽然<code>SELECT</code>可以用作计算，但它并不是SQL的强项。但是，不带<code>FROM</code>子句的<code>SELECT</code>语句有一个有用的用途，就是用来判断当前到数据库的连接是否有效。许多检测工具会执行一条<code>SELECT 1;</code>来测试数据库连接。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token number">1</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这也是我们在使用大部分数据库连接软件测试连接时使用的语句。</p><p><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Git_notes/image-20220908003854140.png" alt="image-20220908003854140" loading="lazy"></p><h3 id="_3-2-条件查询" tabindex="-1"><a class="header-anchor" href="#_3-2-条件查询" aria-hidden="true">#</a> 3.2. 条件查询</h3><p>也就是执行选择操作，关键字是：<code>WHERE</code></p><p>指定哪些行出现在结果中</p><ul><li>单条件选择</li><li>多条件选择</li><li>选择范围</li></ul><h4 id="_3-2-1-单条件选择" tabindex="-1"><a class="header-anchor" href="#_3-2-1-单条件选择" aria-hidden="true">#</a> 3.2.1.单条件选择</h4><p>标准结构</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  列<span class="token number">1</span><span class="token punctuation">,</span>
  列<span class="token number">2</span>
<span class="token keyword">FROM</span> 表名
<span class="token keyword">WHERE</span>
  列<span class="token number">3</span> <span class="token operator">=</span> 值
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>关系运算符包括：<code>&gt; &gt;= &lt; &lt;= = !=</code></p><h4 id="_3-2-2-多条件选择" tabindex="-1"><a class="header-anchor" href="#_3-2-2-多条件选择" aria-hidden="true">#</a> 3.2.2.多条件选择</h4><p>标准结构</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  列A<span class="token punctuation">,</span>
  列B
<span class="token keyword">FROM</span> 表
<span class="token keyword">WHERE</span>
  条件<span class="token number">1</span> 
    <span class="token operator">AND</span> 或者 <span class="token operator">OR</span> 或者 <span class="token operator">NOT</span>
  条件<span class="token number">2</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中<code>AND</code>表示并且，<code>OR</code>表示或者，<code>NOT</code>表示排序符合此条件的记录。</p><p>如：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">select</span> 
  s_id <span class="token punctuation">,</span> 
  s_name 
<span class="token keyword">from</span> students 
<span class="token keyword">where</span> 
  s_id <span class="token operator">&lt;</span> <span class="token number">8</span> 
    <span class="token operator">and</span> 
  s_sex <span class="token operator">=</span> <span class="token string">&#39;男&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果不加括号，条件运算按照<code>NOT</code>、<code>AND</code>、<code>OR</code>的优先级进行，即<code>NOT</code>优先级最高，其次是<code>AND</code>，最后是<code>OR</code>。加上括号可以改变优先级。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">select</span> 
  s_id <span class="token punctuation">,</span> 
  s_name 
<span class="token keyword">from</span> students 
<span class="token keyword">where</span> 
  <span class="token punctuation">(</span>s_id <span class="token operator">&lt;</span> <span class="token number">8</span> <span class="token operator">or</span> s_age<span class="token operator">&gt;</span><span class="token number">23</span><span class="token punctuation">)</span>
<span class="token operator">and</span> 
  s_sex <span class="token operator">=</span> <span class="token string">&#39;男&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里就会先执行<code>or</code>，然后再执行后面的<code>and</code>，我们在实际使用中遇到多个条件运算符时，尽量加上括号，方便更好的阅读。</p><h4 id="_3-2-3-选择范围" tabindex="-1"><a class="header-anchor" href="#_3-2-3-选择范围" aria-hidden="true">#</a> 3.2.3. 选择范围</h4><p>关键字：<code>BETWEEN</code></p><p><code>BETWEEN</code>后的值为从下限到上限。</p><p>如：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  student_age <span class="token operator">BETWEEN</span> <span class="token number">20</span>
  <span class="token operator">AND</span> <span class="token number">23</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e858c9c504f4bcb04d3bc84.jpg" alt="" loading="lazy"></p><h3 id="_3-3-投影查询" tabindex="-1"><a class="header-anchor" href="#_3-3-投影查询" aria-hidden="true">#</a> 3.3. 投影查询</h3><p>用于指定查询结果中能显示哪些列。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列<span class="token number">1</span><span class="token punctuation">,</span> 列<span class="token number">2</span> <span class="token keyword">FROM</span> 表名
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>多个列中间用逗号隔开，如果选择所有列可以用<code>*</code>号简写。</p><p>还是此表：</p><p><img src="https://pic.downk.cc/item/5e858953504f4bcb04d15f04.jpg" alt="" loading="lazy"></p><p>现在只想要查看姓名和年龄列：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> student_name<span class="token punctuation">,</span> student_age <span class="token keyword">FROM</span> t_student<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e858b21504f4bcb04d2a9a9.jpg" alt="" loading="lazy"></p><h4 id="_3-3-1-组合查询" tabindex="-1"><a class="header-anchor" href="#_3-3-1-组合查询" aria-hidden="true">#</a> 3.3.1. 组合查询</h4><p>当我们需要将两列的数据放在一列（字段）中时，可以使用<code>CONCAT</code>来进行组合查询。</p><p>注意这里不是把其他列删除了，而是只显示我们想看见的部分。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> CONCAT<span class="token punctuation">(</span>student_name<span class="token punctuation">,</span> <span class="token string">&#39;——&#39;</span><span class="token punctuation">,</span> student_age<span class="token punctuation">)</span> <span class="token string">&#39;组合值&#39;</span> <span class="token keyword">FROM</span> t_student<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>CONCAT</code>中除了需要的列（字段），还可以添加字符将列与列之间用想要的符号连接起来，这里使用的是字符<code>&#39;--&#39;</code> 。</p><p><img src="https://pic.downk.cc/item/5e858b6d504f4bcb04d2e262.jpg" alt="" loading="lazy"></p><h4 id="_3-3-2-排除重复" tabindex="-1"><a class="header-anchor" href="#_3-3-2-排除重复" aria-hidden="true">#</a> 3.3.2. 排除重复</h4><p>使用<code>DISTINCT</code>。</p><p>现给原表加入一班级列<code>student_class</code>。</p><p><img src="https://pic.downk.cc/item/5e858baa504f4bcb04d30d15.jpg" alt="" loading="lazy"></p><p>查询班级列得到：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> student_class <span class="token keyword">FROM</span> t_student<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e858bba504f4bcb04d31704.jpg" alt="" loading="lazy"></p><p>但是我们只想查看具体有哪些班级，这里就需要用到去重，也就是<code>DISTINCT</code>。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token keyword">DISTINCT</span> student_class <span class="token keyword">FROM</span> t_student<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e858bd7504f4bcb04d32e9b.jpg" alt="" loading="lazy"></p><h4 id="_3-3-3-定义集合" tabindex="-1"><a class="header-anchor" href="#_3-3-3-定义集合" aria-hidden="true">#</a> 3.3.3. 定义集合</h4><p><code>IN</code>或<code>NOT IN</code>。</p><p>现在想查看年龄为17、20、23的学生信息：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  student_age <span class="token operator">IN</span> <span class="token punctuation">(</span><span class="token number">17</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token number">23</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e858cca504f4bcb04d3d9f6.jpg" alt="" loading="lazy"> 反之<code>NOT IN</code>就是选择不包括在集合里的学生信息。</p><h4 id="_3-3-4-模糊查询" tabindex="-1"><a class="header-anchor" href="#_3-3-4-模糊查询" aria-hidden="true">#</a> 3.3.4. 模糊查询</h4><p><code>LIKE</code>。</p><p>为了更好的解释模糊查询，这里重新建张表<code>tt_student</code>。</p><p><img src="https://pic.downk.cc/item/5e858ce6504f4bcb04d3ea6c.jpg" alt="" loading="lazy"></p><p>这里姓王的兄弟们躺枪...别介意。</p><p><strong>首先先说下占位符与通配符：</strong></p><p>占位符 <code>_</code>，表示任何单个字符。</p><p>通配符 <code>%</code>，表示包含零或多个字符。</p><p>下面就来用模糊查询逐一选中我们想要的行。</p><p><strong>名字只有两个字的：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  student_name <span class="token operator">LIKE</span> <span class="token string">&#39;__&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里可能看不清，引号里实际是两个占位符。</p><p><img src="https://pic.downk.cc/item/5e858d07504f4bcb04d400b9.jpg" alt="" loading="lazy"></p><p><strong>所有姓王的：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  student_name <span class="token operator">LIKE</span> <span class="token string">&#39;王%&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e858d22504f4bcb04d411df.jpg" alt="" loading="lazy"></p><p><strong>最后一个字是“王”的：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  student_name <span class="token operator">LIKE</span> <span class="token string">&#39;%王&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e858d59504f4bcb04d43c32.jpg" alt="" loading="lazy"><strong>只要是名字中有“王”字的：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  student_name <span class="token operator">LIKE</span> <span class="token string">&#39;%王%&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e858d69504f4bcb04d448d9.jpg" alt="" loading="lazy"> 这下模糊查询就很明白了吧，当然还有其他组合，大家可以自己尝试。</p><blockquote><p><code>LIKE</code>是模糊查询这些数据，<code>NOT LIKE</code>刚好相反，也就是不需要这些模糊查询出来的数据。</p></blockquote><h4 id="_3-3-5-处理空值数据" tabindex="-1"><a class="header-anchor" href="#_3-3-5-处理空值数据" aria-hidden="true">#</a> 3.3.5. 处理空值数据</h4><p>判断条件不能用<code>列名=NULL</code>，而是要用<code>IS NULL</code>或<code>IS NOT NULL</code>。</p><p><strong>标准写法：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  student_age <span class="token operator">IS</span> <span class="token boolean">NULL</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-4-排序查询" tabindex="-1"><a class="header-anchor" href="#_3-4-排序查询" aria-hidden="true">#</a> 3.4. 排序查询</h3><p><code>ORDER BY</code>。</p><p>指定查询的结果以什么样的顺序显示。</p><p>使用<code>ORDER BY</code>时，列名上指定<code>ASC</code>或<code>DESC</code>。<code>ASC</code>表示正序，<code>DESC</code>表示倒序。如果不指定则默认为正序。</p><p><strong>按年龄排：</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">ORDER</span> <span class="token keyword">BY</span>
  student_age <span class="token keyword">ASC</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e858dc8504f4bcb04d4a68a.jpg" alt="" loading="lazy"></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">ORDER</span> <span class="token keyword">BY</span>
  student_age <span class="token keyword">DESC</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e858dc8504f4bcb04d4a68a.jpg" alt="" loading="lazy"></p><h3 id="_3-5-分页查询" tabindex="-1"><a class="header-anchor" href="#_3-5-分页查询" aria-hidden="true">#</a> 3.5. 分页查询</h3><p><code>LIMIT</code></p><p>使用SELECT查询时，如果结果集数据量很大，比如几万行数据，放在一个页面显示的话数据量太大，且对数据库的压力也大，不如分页显示，每次显示100条，也每次从数据库拿100条数据。</p><p>要实现分页功能，实际上就是从结果集中显示第1<sub>100条记录作为第1页，显示第101</sub>200条记录作为第2页，以此类推。</p><p>因此，分页实际上就是从结果集中“截取”出第M~N条记录。这个查询可以通过<code>LIMIT N OFFSET M</code>子句实现。</p><p>其中：</p><p>LIMIT 为返回限定行数的查询，</p><p><code>LIMIT N</code> 表示从第一行开始返回 <code>N</code> 行结果;</p><p><code>LIMIT N OFFSET M</code>中的<code>OFFSET M</code>为偏移量，就记录集索引<code>M</code>之前的数据不管，从索引<code>M</code>开始返回<code>N</code>行结果。</p><h4 id="_3-5-1-实操步骤" tabindex="-1"><a class="header-anchor" href="#_3-5-1-实操步骤" aria-hidden="true">#</a> 3.5.1. 实操步骤</h4><p>这里使用上面模糊操作中的表<code>tt_student</code>训练。</p><ol><li>我们先把所有学生按照年龄从高到低进行排序：</li></ol><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 按student_age从高到低</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> tt_students <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> student_age <span class="token keyword">DESC</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>把结果集分页，每页4条记录。要获取第1页的记录，可以使用<code>LIMIT 4 OFFSET 0</code>：</li></ol><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 查询第1页</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> 
<span class="token keyword">FROM</span> tt_students 
<span class="token keyword">ORDER</span> <span class="token keyword">BY</span> student_age <span class="token keyword">DESC</span> 
<span class="token keyword">LIMIT</span> <span class="token number">4</span> <span class="token keyword">OFFSET</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token comment">-- 或者使用下面语句</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> 
<span class="token keyword">FROM</span> t_students 
<span class="token keyword">ORDER</span> <span class="token keyword">BY</span> student_age <span class="token keyword">DESC</span> 
<span class="token keyword">LIMIT</span> <span class="token number">4</span> <span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上述查询<code>LIMIT 4 OFFSET 0</code>表示，对结果集从0号记录开始，最多取4条。注意SQL记录集的索引从0开始。</p><ol start="3"><li>如果要查询第2页，那么我们只需要“跳过”头4条记录，也就是对结果集从索引为4号的记录开始查询，把<code>OFFSET</code>设定为4。</li></ol><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 查询第2页</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> 
<span class="token keyword">FROM</span> t_students 
<span class="token keyword">ORDER</span> <span class="token keyword">BY</span> student_age <span class="token keyword">DESC</span> 
<span class="token keyword">LIMIT</span> <span class="token number">4</span> <span class="token keyword">OFFSET</span> <span class="token number">4</span><span class="token punctuation">;</span>
<span class="token comment">-- 或者使用下面语句</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> 
<span class="token keyword">FROM</span> t_students 
<span class="token keyword">ORDER</span> <span class="token keyword">BY</span> student_age <span class="token keyword">DESC</span> 
<span class="token keyword">LIMIT</span> <span class="token number">4</span> <span class="token number">4</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>由于表<code>tt_students</code>只有6条数据，因此第2页只有2条记录，因此最终的结果集按实际数量2显示，\`LIMIT 4表示的意思是“最多4条记录”。</p><p>如果后续还存在别的页，那么查询第3页的时候，<code>OFFSET</code>应该设定为8；</p><p>查询第4页的时候，<code>OFFSET</code>应该设定为12。</p><p>可见，分页查询的关键在于，首先要确定每页需要显示的结果数量<code>pageSize</code>（这里是4），然后根据当前页的索引<code>pageIndex</code>（从1开始），确定<code>LIMIT</code>和<code>OFFSET</code>应该设定的值：</p><ul><li><code>LIMIT = pageSize</code>；</li><li><code>OFFSET = pageSize * (pageIndex - 1)</code>。</li></ul><p>这样就能正确查询出第N页的记录集。</p><p>原本表<code>tt_student</code>一共就6条记录，但我们把<code>OFFSET</code>设置为20，会得到什么结果呢？</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- OFFSET设定为20</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> 
<span class="token keyword">FROM</span> t_students 
<span class="token keyword">ORDER</span> <span class="token keyword">BY</span> student_age <span class="token keyword">DESC</span> 
<span class="token keyword">LIMIT</span> <span class="token number">4</span> <span class="token keyword">OFFSET</span> <span class="token number">20</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>OFFSET</code>超过了查询的最大数量并不会报错，而是得到一个空的结果集。</p><h4 id="_3-5-2-注意" tabindex="-1"><a class="header-anchor" href="#_3-5-2-注意" aria-hidden="true">#</a> 3.5.2. 注意</h4><p><code>OFFSET</code>是可选的，如果只写<code>LIMIT 15</code>，那么相当于<code>LIMIT 15 OFFSET 0</code>。</p><p>在MySQL中，<code>LIMIT 15 OFFSET 30</code>还可以简写成<code>LIMIT 30, 15</code>。</p><p>使用<code>LIMIT &lt;M&gt; OFFSET &lt;N&gt;</code>分页时，随着<code>N</code>越来越大，查询效率也会越来越低。</p><h4 id="_3-5-3-小结" tabindex="-1"><a class="header-anchor" href="#_3-5-3-小结" aria-hidden="true">#</a> 3.5.3. 小结</h4><p>使用<code>LIMIT &lt;M&gt; OFFSET &lt;N&gt;</code>可以对结果集进行分页，每次查询返回结果集的一部分；</p><p>分页查询需要先确定每页的数量和当前页数，然后确定<code>LIMIT</code>和<code>OFFSET</code>的值。</p><h4 id="_3-5-4-思考" tabindex="-1"><a class="header-anchor" href="#_3-5-4-思考" aria-hidden="true">#</a> 3.5.4. 思考</h4><p>在分页查询之前，如何计算一共有几页（<code>totalPage</code>）？</p><p>这部分可以通过后面学习聚合查询时获取总的数据量（<code>totalSize</code>），然后可以整除的情况下<code>totalPage = totalSize/pageSize</code>，不能整除还有余数的情况下，<code>totalPage = totalSize/pageSize+1</code>，这里是否整除可以判断<code>totalSize%pageSize==0</code>是否为<code>true</code>来确定。</p><h2 id="_4-基本查询sql的执行顺序-极重要" tabindex="-1"><a class="header-anchor" href="#_4-基本查询sql的执行顺序-极重要" aria-hidden="true">#</a> 4. 基本查询SQL的执行顺序（极重要）</h2><ol><li>执行<code>FROM </code></li><li><code>WHERE</code>条件过滤</li><li><code>SELECT</code>投影</li><li><code>ORDER BY</code>排序</li></ol><p>还有聚合查询和多表查询，我们在第三节学习。</p>`,172),p=[l];function c(o,i){return n(),a("div",null,p)}const r=s(d,[["render",c],["__file","2.html.vue"]]);export{r as default};
